/// <summary>
/// New table for the application dimension values in the ETGSPAIN model.
/// </summary>
public class ETGSPAINInventApplicationTable extends common
{
}

Method.Source:
/// <summary>
/// Method to find a record.
/// </summary>
/// <param name="_applicationId">Application ID number</param>
/// <param name="_forUpdate">Whether to update the record</param>
/// <returns>The found value</returns>
public static ETGSPAINInventApplicationTable find(ETGSPAINInventApplicationId _applicationId, boolean _forUpdate = false)
{
    ETGSPAINInventApplicationTable ETGSPAINInventApplicationTable;

    if (_applicationId)
    {
        if (_forUpdate)
        {
            ETGSPAINInventApplicationTable.selectForUpdate(_forUpdate);
        }

        select firstonly ETGSPAINInventApplicationTable
            index hint ApplicationIdIdx
            where ETGSPAINInventApplicationTable.ApplicationId == _applicationId;
    }

    return ETGSPAINInventApplicationTable;
}

/// <summary>
/// Method to check if the record exists.
/// </summary>
/// <param name="_applicationId">Application number</param>
/// <returns>True if the record exists, otherwise false</returns>
public static boolean exist(ETGSPAINInventApplicationId _applicationId)
{
    return _applicationId && (select firstonly RecId from ETGSPAINInventApplicationTable
        index hint ApplicationIdIdx
        where ETGSPAINInventApplicationTable.ApplicationId == _applicationId).RecId != 0;
}

/// <summary>
/// Method to find or create a record.
/// </summary>
/// <param name="_applicationId">Application ID number</param>
/// <param name="_forUpdate">Whether to update the record</param>
/// <returns>The found or newly created value</returns>
public static ETGSPAINInventApplicationTable findOrCreate(ETGSPAINInventApplicationId _applicationId, boolean _forUpdate = false)
{
    if (!ETGSPAINInventApplicationTable::exist(_applicationId))
    {
        ETGSPAINInventApplicationTable ETGSPAINInventApplicationTable;

        ttsbegin;
        ETGSPAINInventApplicationTable.ApplicationId    = _applicationId;
        ETGSPAINInventApplicationTable.Description      = _applicationId;
        ETGSPAINInventApplicationTable.insert();
        ttscommit;
    }

    return ETGSPAINInventApplicationTable::find(_applicationId, _forUpdate);
}
